def gen(rng, size):
    n = max(1, size)
    nums1 = [rng.randint(1, n) for _ in range(n)]
    nums2 = []
    for i in range(n):
        if rng.random() < 0.3:
            nums2.append(nums1[i])
        else:
            nums2.append(rng.randint(1, n))
    return [nums1, nums2]

