class Solution:
    def minimumTotalCost(self, nums1, nums2):
        from itertools import permutations
        n = len(nums1)
        bad_mask = 0
        for i in range(n):
            if nums1[i] == nums2[i]:
                bad_mask |= (1 << i)
        best = None
        for mask in range(1 << n):
            if (mask & bad_mask) != bad_mask:
                continue
            idxs = [i for i in range(n) if mask & (1 << i)]
            if len(idxs) == 1:
                continue
            if not idxs:
                cost = 0
            else:
                values = [nums1[i] for i in idxs]
                feasible = False
                for perm in permutations(values):
                    if all(perm[k] != nums2[idxs[k]] for k in range(len(idxs))):
                        feasible = True
                        break
                if not feasible:
                    continue
                cost = sum(idxs)
            if best is None or cost < best:
                best = cost
        return best if best is not None else -1

