class Solution:
    def minimumTotalCost(self, nums1, nums2):
        n = len(nums1)
        from collections import Counter
        cost = 0
        count = 0
        freq = Counter()
        max_freq = 0
        max_val = 0
        for i in range(n):
            if nums1[i] == nums2[i]:
                cost += i
                count += 1
                freq[nums1[i]] += 1
                if freq[nums1[i]] > max_freq:
                    max_freq = freq[nums1[i]]
                    max_val = nums1[i]
        if count == 0:
            return 0
        for i in range(n):
            if max_freq * 2 <= count:
                break
            if nums1[i] != nums2[i] and nums1[i] != max_val and nums2[i] != max_val:
                cost += i
                count += 1
        if max_freq * 2 > count:
            return -1
        return cost

