var minimumTotalCost = function(nums1, nums2) {
    const n = nums1.length;
    let cost = 0;
    let count = 0;
    const freq = new Map();
    let maxFreq = 0;
    let maxVal = 0;
    for (let i = 0; i < n; i++) {
        if (nums1[i] === nums2[i]) {
            cost += i;
            count++;
            const f = (freq.get(nums1[i]) || 0) + 1;
            freq.set(nums1[i], f);
            if (f > maxFreq) {
                maxFreq = f;
                maxVal = nums1[i];
            }
        }
    }
    if (count === 0) return 0;
    for (let i = 0; i < n; i++) {
        if (maxFreq * 2 <= count) break;
        if (nums1[i] !== nums2[i] && nums1[i] !== maxVal && nums2[i] !== maxVal) {
            cost += i;
            count++;
        }
    }
    if (maxFreq * 2 > count) return -1;
    return cost;
};
